-- Front Plank (front-plank) [insert]
UPDATE coaching.exercise SET
  name = 'Front Plank',
  description = 'Front Plank is an isometric exercise using the prone forearm plank to develop core, spine, shoulder control, tissue tolerance, and force expression without visible joint movement.',
  card_summary = 'Prone trunk hold that teaches anti-extension, rib-pelvis stacking, and whole-body tension without motion.',
  coach_language = 'Primary subrole: trunk_pelvis_anti_movement_control. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.',
  athlete_language = 'Own the position, build steady pressure, breathe, and stop before the shape changes.',
  movement_family = 'Anti-extension trunk isometric',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'front_plank_anti_extension_hold',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 40,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["spine_anti_extension","shoulder_support","hip_extension_lock","pelvic_control"],"primary_tissues":["anterior_core","glutes","serratus_anterior","hip_flexors"],"primary_motor_control_demands":["rib_pelvis_stack","anti_extension","whole_body_tension"],"postural_shape":"prone forearm plank","breathing_demand":"quiet nasal or controlled open-glottis breathing","balance_demand":"stable floor support","coordination_demand":"low","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Set up in the prone forearm plank. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the prone forearm plank.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 20 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Long body, ribs down","Push the floor away","Squeeze glutes without holding breath"],"athlete_cues":["Own the angle.","Pressure without panic.","Breathe while you hold."],"breathing_cues":["No breath-holding contest.","Small exhale through the brace.","Reset breath between hard efforts."],"common_faults":["Hips sag or pike","Breath is held","Shoulders collapse toward ears"],"quality_gate":"Rep counts only when the athlete holds the chosen angle with steady pressure, controlled breathing, and no visible compensation.","stop_signs":["Pain, pinch, numbness, tingling, dizziness, or headache","Breath holding that cannot be corrected","Alignment changes or shaking becomes uncontrolled","Unsafe equipment, anchor, wall, rack, or landing setup"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Related strength pattern","Related movement-skill pattern","Resilience accessory work"],"pairs_well_after":["General warmup","Pattern-specific mobility","Breathing or activation reset"],"good_for_sessions":["general_warmup","core_control","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the target joint or tissue","Athlete cannot maintain alignment or breathe during the hold","The setup is unstable or the athlete lacks a safe exit","The session priority is fresh max-speed, jump, or power output and this hold would create fatigue first"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex isometric demo recommended","Vortex Exercise Card Authoring Guide: isometrics phase and taxonomy rules","Isometric training literature: joint-angle specificity, muscle length, intensity, and intent considerations"],"internal_notes":["Film Front Plank from the angle that best shows core, spine, shoulder alignment.","Show one easy regression and one advanced progression.","Coach breathing and exact stop rules; do not only show the end position."]}'::jsonb,
  updated_at = now()
WHERE slug = 'front-plank';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', 'front_plank_anti_extension_hold', pos.order_index,
  FALSE, 3, 2,
  2, 0, 'moderate'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'resilience'
JOIN coaching.phase_order_slot pos ON pos.key = 'front_plank_anti_extension_hold' AND pos.phase_id = sp.id
WHERE e.slug = 'front-plank'
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role,
  order_slot = EXCLUDED.order_slot,
  order_index = EXCLUDED.order_index,
  fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required,
  fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost,
  technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level,
  intensity_ceiling = EXCLUDED.intensity_ceiling;

