-- Isometric Ankle Inversion Press (isometric-ankle-inversion-press) [insert]
UPDATE coaching.exercise SET
  name = 'Isometric Ankle Inversion Press',
  description = 'Isometric Ankle Inversion Press is an isometric exercise using the seated or standing ankle inward press against immovable surface to develop ankle, foot, calf control, tissue tolerance, and force expression without visible joint movement.',
  card_summary = 'Controlled inward ankle pressure drill that builds medial ankle control and foot/ankle tissue tolerance.',
  coach_language = 'Primary subrole: single_leg_balance_foot_ankle_hip_control. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.',
  athlete_language = 'Own the position, build steady pressure, breathe, and stop before the shape changes.',
  movement_family = 'Medial ankle isometric',
  primary_phase_key = 'resilience',
  phase_subrole = 'single_leg_balance_foot_ankle_hip_control',
  primary_order_slot = 'ankle_inversion_iso_press',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 10,
  default_rest_seconds = 25,
  est_seconds_per_set = 35,
  movement_requirements = '{"primary_joint_actions":["ankle_inversion_isometric","foot_arch_control","toe_pressure_control","knee_alignment_control"],"primary_tissues":["tibialis_posterior","foot_intrinsics","calves","medial_ankle_tissues"],"primary_motor_control_demands":["medial_ankle_pressure","arch_ownership","pain_free_force_direction"],"postural_shape":"seated or standing ankle inward press against immovable surface","breathing_demand":"normal breathing","balance_demand":"stable seated or supported stance","coordination_demand":"low","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Set up in the seated or standing ankle inward press against immovable surface. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the seated or standing ankle inward press against immovable surface.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 10 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Press smoothly, not suddenly","Keep toes relaxed","Feel control around the ankle, not pain"],"athlete_cues":["Own the angle.","Pressure without panic.","Breathe while you hold."],"breathing_cues":["No breath-holding contest.","Small exhale through the brace.","Reset breath between hard efforts."],"common_faults":["Cramping toes","Twisting the knee to fake ankle motion","Too much pressure too soon"],"quality_gate":"Rep counts only when the athlete holds the chosen angle with steady pressure, controlled breathing, and no visible compensation.","stop_signs":["Pain, pinch, numbness, tingling, dizziness, or headache","Breath holding that cannot be corrected","Alignment changes or shaking becomes uncontrolled","Unsafe equipment, anchor, wall, rack, or landing setup"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Related strength pattern","Related movement-skill pattern","Resilience accessory work"],"pairs_well_after":["General warmup","Pattern-specific mobility","Breathing or activation reset"],"good_for_sessions":["ankle_resilience","return_to_play_capacity","foot_control"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the target joint or tissue","Athlete cannot maintain alignment or breathe during the hold","The setup is unstable or the athlete lacks a safe exit","The session priority is fresh max-speed, jump, or power output and this hold would create fatigue first"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex isometric demo recommended","Vortex Exercise Card Authoring Guide: isometrics phase and taxonomy rules","Isometric training literature: joint-angle specificity, muscle length, intensity, and intent considerations"],"internal_notes":["Film Isometric Ankle Inversion Press from the angle that best shows ankle, foot, calf alignment.","Show one easy regression and one advanced progression.","Coach breathing and exact stop rules; do not only show the end position."]}'::jsonb,
  updated_at = now()
WHERE slug = 'isometric-ankle-inversion-press';

