  default_distance = NULL::integer,
  default_work_seconds = 8,
  default_rest_seconds = 40,
  est_seconds_per_set = 48,
  default_rpe_min = 3,
  default_rpe_max = 5,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'bear-plank-shoulder-tap-iso-hold';

