INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'youth_beginner', 'youth beginner', 'baseline', v.guidance,
  CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('front-plank', 'Use the easiest stable version of Front Plank: shorten the hold to 5-10 seconds, add wall/bench/coach support, and stop every rep while breathing and position are still clean.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
