UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'older_adult' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('front-plank', 'Use stable support, low-to-moderate effort, and shorter holds. Avoid breath holding, dizziness, or positions that create fall risk; prioritize confidence and clean breathing.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('side-plank', 'Use stable support, low-to-moderate effort, and shorter holds. Avoid breath holding, dizziness, or positions that create fall risk; prioritize confidence and clean breathing.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
