  ('farmer-hold', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('front-rack-hold', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('zercher-hold', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('isometric-mid-thigh-pull', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('trap-bar-pin-pull-iso', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('squat-pin-iso', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('bench-press-pin-iso', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
  ('split-stance-cable-pallof-iso-hold', 'Use comfortable positions, avoid prolonged breath holding or high intra-abdominal pressure, reduce hold duration, and choose side-lying, seated, or supported alternatives when needed.', 'No default gender adjustment; scale by training age, symptoms, joint tolerance, strength level, pregnancy/postpartum status, and current readiness rather than gender alone.'),
