  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for isometric position ownership, tissue tolerance, and joint-angle force expression.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('front-plank', 'Front Plank removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / trunk_pelvis_anti_movement_control because the primary training problem is isometric position ownership for core, spine, shoulder. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use after the warm-up as trunk control prep, in Resilience after main work, or as a low-fatigue bridge before crawling or loaded bracing.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('side-plank', 'Side Plank removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / trunk_pelvis_anti_movement_control because the primary training problem is isometric position ownership for core, spine, shoulder. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or trunk prep before carries, change-of-direction, throwing, or unilateral lower-body work.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('hollow-body-hold', 'Hollow Body Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in movement_intelligence / shape_position_intelligence because the primary training problem is isometric position ownership for core, spine, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use early in Movement Intelligence before tumbling, handstand, crawling, or calisthenics skill work; keep it crisp and non-fatiguing.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('dead-bug-iso-press', 'Dead Bug Iso Press removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in prepare_and_access / activate because the primary training problem is isometric position ownership for core, spine, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Prepare & Access before lifting, sprint mechanics, crawling, or athletes who need rib-pelvis organization before higher-intent work.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('bear-hover-hold', 'Bear Hover Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in movement_intelligence / shape_position_intelligence because the primary training problem is isometric position ownership for core, shoulder, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Movement Intelligence before crawls, locomotion flows, grappling prep, or bodyweight strength blocks.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('pallof-press-iso-hold', 'Pallof Press Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / trunk_pelvis_anti_movement_control because the primary training problem is isometric position ownership for core, spine, shoulder. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after main work or before rotational sport practice when the goal is position ownership, not fatigue.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('copenhagen-side-plank', 'Copenhagen Side Plank removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for hip, core, knee. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after speed, change-of-direction, or lower-body strength work; start with short-lever versions before progressing.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('bird-dog-iso-hold', 'Bird Dog Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in movement_intelligence / shape_position_intelligence because the primary training problem is isometric position ownership for core, spine, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Movement Intelligence or Prepare & Access before crawls, hinging, running mechanics, or low-back-sensitive sessions.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('glute-bridge-iso-hold', 'Glute Bridge Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in prepare_and_access / activate because the primary training problem is isometric position ownership for hip, core, spine. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Prepare & Access before lower-body strength, sprinting, field work, or athletes who need hip extension access before loading.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('suitcase-hold', 'Suitcase Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in capacity / carry_trunk_loaded_bracing_strength because the primary training problem is isometric position ownership for core, forearm, shoulder. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Capacity after general preparation and before hard conditioning; pair with unilateral lower-body work, carries, or trunk bracing blocks.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('wall-sit', 'Wall Sit removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in capacity / squat_knee_dominant_strength because the primary training problem is isometric position ownership for knee, hip, ankle. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Capacity or Resilience after warm-up; keep it away from true Output if fatigue would blunt sprint or jump quality.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('split-squat-iso-hold', 'Split Squat Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in capacity / squat_knee_dominant_strength because the primary training problem is isometric position ownership for hip, knee, ankle. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Capacity before or after dynamic split squats, step-ups, or deceleration work; reduce duration if alignment fades.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('spanish-squat-hold', 'Spanish Squat Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for knee, hip, ankle. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or knee-capacity blocks after main speed and strength work; keep pain-free and controlled.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('goblet-squat-bottom-iso-hold', 'Goblet Squat Bottom Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in capacity / squat_knee_dominant_strength because the primary training problem is isometric position ownership for hip, knee, ankle. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Capacity after mobility and warm-up, before dynamic squat work as a positional primer or after as accessory strength.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('cossack-bottom-hold', 'Cossack Bottom Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for hip, knee, ankle. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after main work or as low-dose movement prep before lateral training when the athlete can control range.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('hip-airplane-iso-hold', 'Hip Airplane Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in movement_intelligence / balance_coordination_rhythm because the primary training problem is isometric position ownership for hip, ankle, core. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Movement Intelligence before single-leg strength, cutting mechanics, skating, field sports, or hinge training.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('single-leg-glute-bridge-iso-hold', 'Single-Leg Glute Bridge Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / trunk_pelvis_anti_movement_control because the primary training problem is isometric position ownership for hip, core, spine. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or lower-body preparation before sprinting, hinging, or unilateral strength.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('long-lever-hamstring-bridge-iso-hold', 'Long-Lever Hamstring Bridge Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for hamstrings, hip, core. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after sprinting or lower-body strength; keep duration short enough that cramping and pelvis drop do not dominate.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('nordic-hamstring-iso-hold', 'Nordic Hamstring Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for hamstrings, knee, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after sprinting or strength work, never as a fatigue finisher before high-speed running.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('hip-flexor-march-iso-hold', 'Hip Flexor March Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in prepare_and_access / activate because the primary training problem is isometric position ownership for hip, core, spine. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Prepare & Access before sprint drills, marching/skipping mechanics, kicking, or field-sport work.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('standing-calf-raise-iso-hold', 'Standing Calf Raise Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for ankle, foot, calf. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or lower-leg capacity after sprint/jump work, or as low-impact prep when contacts must be limited.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('bent-knee-soleus-wall-sit-hold', 'Bent-Knee Soleus Wall Sit Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for ankle, calf, knee. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience after speed or jump work, or on low-impact days that need ankle and calf capacity.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('tibialis-raise-iso-hold', 'Tibialis Raise Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / slow_eccentric_isometric_joint_resilience because the primary training problem is isometric position ownership for ankle, shin, foot. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience, lower-leg prep, or return-to-run sessions; dose modestly to avoid shin irritation.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('wall-ankle-dorsiflexion-iso-press', 'Wall Ankle Dorsiflexion Iso Press removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in prepare_and_access / mobilize because the primary training problem is isometric position ownership for ankle, foot, knee. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Prepare & Access before squats, lunges, landing work, sprint starts, or athletes who need ankle access without passive stretching.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('isometric-ankle-inversion-press', 'Isometric Ankle Inversion Press removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / single_leg_balance_foot_ankle_hip_control because the primary training problem is isometric position ownership for ankle, foot, calf. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or foot/ankle prep after general warm-up; keep pressure low-to-moderate and pain-free.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('isometric-ankle-eversion-press', 'Isometric Ankle Eversion Press removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in resilience / single_leg_balance_foot_ankle_hip_control because the primary training problem is isometric position ownership for ankle, foot, calf. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Resilience or foot/ankle prep after warm-up, especially before lateral movement progressions or return-to-play work.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('foot-tripod-single-leg-balance-hold', 'Foot Tripod Single-Leg Balance Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in movement_intelligence / balance_coordination_rhythm because the primary training problem is isometric position ownership for foot, ankle, hip. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Movement Intelligence or Prepare & Access before running, cutting, jumping, or unilateral lifting.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
  ('big-toe-press-iso-hold', 'Big Toe Press Iso Hold removes visible movement so the athlete can create force, organize posture, and feel the target tissues at a precise joint angle. The static demand makes compensation easier to see and lets the coach scale intensity, range, and duration without adding impact.', 'Belongs in prepare_and_access / activate because the primary training problem is isometric position ownership for foot, ankle, calf. It should be placed where it supports readiness, force production, or resilience without stealing quality from faster work.', 'Use in Prepare & Access before lower-body training when foot pressure or arch control needs attention.', 'Do not turn the hold into a breath-holding contest, pain-tolerance challenge, or fatigue finisher. The set is over when alignment, breathing, or target-tissue tension is lost.', 'Scale isometrics first by position quality, then by hold duration, then by external load or intent. A harder hold is not better if it forces pain, breath holding, or compensation.'),
